def is_aspirated_english(consonant_ipa, word_position='start'):
    aspirated_consonants = {'p ∞', 't ∞', 'k ∞', 'tÕ° É ∞'}
    if word_position == 'start' and consonant_ipa in aspirated_consonants:
        return True
    return False

# Example usage:
print(is_aspirated_english('p ∞', 'start'))  # Output: True (aspirated)
print(is_aspirated_english('p', 'start'))    # Output: False (unaspirated)
